// Validate Input Schema AND Preserve Universal Contract Fields
const items = $input.all();
const results = [];

// Get universal contract fields from Execute Workflow Trigger
const triggerData = $('Execute Workflow Trigger').first().json;
const universalContract = {
  request_id: triggerData.request_id || null,
  mode: triggerData.mode || null,
  confidence: triggerData.confidence || null,
  risk_level: triggerData.risk_level || null,
  audit: triggerData.audit || null
};

for (const item of items) {
  const data = item.json;
  let isValid = true;
  let errorMessage = '';

  // Check for required fields
  const requiredFields = ['request_id', 'product_type', 'target_use', 'constraints'];
  const missingFields = [];

  for (const field of requiredFields) {
    if (!data[field]) {
      missingFields.push(field);
      isValid = false;
    }
  }

  if (missingFields.length > 0) {
    errorMessage = `Missing required fields: ${missingFields.join(', ')}`;
  }

  // Validate constraints object
  if (data.constraints && typeof data.constraints === 'object') {
    const requiredConstraintFields = ['budget', 'region', 'allergen_free'];
    const missingConstraintFields = [];

    for (const field of requiredConstraintFields) {
      if (data.constraints[field] === undefined || data.constraints[field] === null) {
        missingConstraintFields.push(field);
        isValid = false;
      }
    }

    if (missingConstraintFields.length > 0) {
      if (errorMessage) errorMessage += '; ';
      errorMessage += `Missing required constraint fields: ${missingConstraintFields.join(', ')}`;
    }
  } else if (data.constraints === undefined) {
    isValid = false;
    if (errorMessage) errorMessage += '; ';
    errorMessage += 'constraints object is required';
  }

  // Set mode from Workflow Configuration if not provided in input or universal contract
  if (!data.mode && !universalContract.mode) {
    data.mode = $('Workflow Configuration').first().json.default_mode || 'simulation';
  }

  // Return validation result merged with universal contract fields
  results.push({
    json: {
      ...universalContract,
      ...data,
      validation: {
        isValid: isValid,
        errorMessage: errorMessage || null
      }
    }
  });
}

return results;

// Return standardized error response for invalid input
const items = $input.all();

// Get validation error from previous node
const validationData = items[0]?.json?.validation || {};
const validationError = validationData.errorMessage || items[0]?.json?.error || 'Invalid or incomplete universal contract';
const requestId = items[0]?.json?.request_id || $execution.id;

return [
  {
    json: {
      status: 'rejected',
      reason: 'Invalid or incomplete universal contract',
      message: validationError,
      request_id: requestId,
      timestamp: new Date().toISOString()
    }
  }
];

