// Filter Valid Formulas for Cost Optimization
// Only pass formulas that passed all previous checks

const items = $input.all();
const inputData = items[0].json;

// Get all formulas
const allFormulas = inputData.formulas || [];

// Get failed formulas from Lab Simulation
const labSimulation = $('Lab Simulation Agent').first().json;
const failedFormulas = labSimulation.failed_formulas || [];

// Get unstable formulas from Stability Simulation
const stabilitySimulation = $('Stability Simulation Agent').first().json;
const unstableFormulas = stabilitySimulation.unstable_formulas || [];

// Get safe formulas from Safety Assessment
const safetyAssessment = $('Safety Assessment Agent').first().json;
const safeFormulas = safetyAssessment.safe_formulas || [];

// Get compliant formulas from Compliance Check (if available)
// Note: This node runs BEFORE Compliance Check, so we'll prepare for it
// We'll filter based on lab, stability, and safety for now

// Filter formulas that passed all checks
const validFormulas = allFormulas.filter(formula => {
  const formulaId = formula.id;

  // Must NOT be in failed formulas
  const notFailed = !failedFormulas.includes(formulaId);

  // Must NOT be in unstable formulas
  const notUnstable = !unstableFormulas.includes(formulaId);

  // Must be in safe formulas
  const isSafe = safeFormulas.includes(formulaId);

  return notFailed && notUnstable && isSafe;
});

// Return all input data with valid_formulas field
return [{
  json: {
    ...inputData,
    valid_formulas: validFormulas,
    validation_summary: {
      total_formulas: allFormulas.length,
      failed_lab: failedFormulas.length,
      failed_stability: unstableFormulas.length,
      passed_safety: safeFormulas.length,
      valid_for_compliance: validFormulas.length
    }
  }
}];

// Universal Contract Validation
// Validates the universal contract structure for all incoming requests

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let isValid = true;
  let errorMessage = '';
  const missingFields = [];

  // Check for required universal contract fields
  const requiredFields = ['request_id', 'mode', 'confidence', 'risk_level', 'payload'];

  for (const field of requiredFields) {
    if (data[field] === undefined || data[field] === null) {
      missingFields.push(field);
      isValid = false;
    }
  }

  // Validate audit metadata if present
  if (data.audit_metadata) {
    if (typeof data.audit_metadata !== 'object') {
      isValid = false;
      errorMessage = 'audit_metadata must be an object';
    }
  }

  // Validate mode value
  if (data.mode && !['simulation', 'production', 'test'].includes(data.mode)) {
    isValid = false;
    if (errorMessage) errorMessage += '; ';
    errorMessage += 'mode must be one of: simulation, production, test';
  }

  // Validate confidence value
  if (data.confidence !== undefined && (typeof data.confidence !== 'number' || data.confidence < 0 || data.confidence > 100)) {
    isValid = false;
    if (errorMessage) errorMessage += '; ';
    errorMessage += 'confidence must be a number between 0 and 100';
  }

  // Validate risk_level value
  if (data.risk_level && !['low', 'medium', 'high', 'critical'].includes(data.risk_level)) {
    isValid = false;
    if (errorMessage) errorMessage += '; ';
    errorMessage += 'risk_level must be one of: low, medium, high, critical';
  }

  // Validate payload exists and is an object
  if (data.payload && typeof data.payload !== 'object') {
    isValid = false;
    if (errorMessage) errorMessage += '; ';
    errorMessage += 'payload must be an object';
  }

  if (missingFields.length > 0) {
    if (errorMessage) errorMessage += '; ';
    errorMessage += `Missing required universal contract fields: ${missingFields.join(', ')}`;
  }

  // Return validation result
  results.push({
    json: {
      ...data,
      universal_contract_validation: {
        isValid: isValid,
        errorMessage: errorMessage || null,
        validated_at: new Date().toISOString()
      }
    }
  });
}

return results;

// System Confidence Recheck
// Check if confidence from WF-0 is sufficient for proceeding

const items = $input.all();
const inputData = items[0].json;

// Get confidence and risk_level from WF-0 (assumed to be in input data)
const confidence = inputData.confidence || inputData.system_confidence || 1.0;
const riskLevel = inputData.risk_level || inputData.riskLevel || 'low';

// Check if confidence is sufficient
// Insufficient if: confidence < 0.9 AND risk_level is NOT 'low'
const confidenceSufficient = !(confidence < 0.9 && riskLevel !== 'low');

let reason = null;
if (!confidenceSufficient) {
  reason = `Confidence level ${confidence} is below threshold (0.9) and risk level is ${riskLevel} (not low). Manual review required.`;
}

return [{
  json: {
    ...inputData,
    confidence_check: {
      confidence_sufficient: confidenceSufficient,
      confidence: confidence,
      risk_level: riskLevel,
      reason: reason,
      threshold: 0.9,
      checked_at: new Date().toISOString()
    }
  }
}];

// Compute Compliance State based on Compliance Check Agent results
const items = $input.all();
const inputData = items[0].json;

// Get compliance results from Compliance Check Agent
const complianceCheck = $('Compliance Check Agent').first().json;
const isCompliant = complianceCheck.compliant;

// Determine compliance state
let complianceState;
if (isCompliant === true) {
  complianceState = 'compliant';
} else if (isCompliant === false) {
  complianceState = 'non_compliant';
} else {
  // If compliant is undefined or null, requires review
  complianceState = 'requires_review';
}

// Return all input data with computed compliance_state field
return [{
  json: {
    ...inputData,
    compliance_state: complianceState,
    compliance_details: {
      compliant: isCompliant,
      violations: complianceCheck.violations || [],
      compliant_formulas: complianceCheck.compliant_formulas || []
    }
  }
}];

// Final Output Sanitization & Normalization
// DROP all internal R&D fields
// REBUILD output with ONLY specified fields

const items = $input.all();
const inputData = items[0].json;

// Extract key data from workflow execution
const requestId = inputData.request_id || $('Execute Workflow Trigger').first().json.request_id || 'unknown';
const afaApproval = $('AFA Final Approval Agent').first().json;
const creaApproval = $('Call CREA Approval (WF-8)').first().json;
const complianceCheck = $('Compliance Check Agent').first().json;
const safetyAssessment = $('Safety Assessment Agent').first().json;

// Determine formulation status
let formulationStatus = 'approved';
let decisionSummary = 'Formulation approved and ready for operations';

if (!afaApproval.approved) {
  formulationStatus = 'rejected';
  decisionSummary = afaApproval.notes || 'AFA rejected the formulation';
} else if (!creaApproval.crea_approved) {
  formulationStatus = 'rejected';
  decisionSummary = 'CREA rejected the formulation';
} else if (!complianceCheck.compliant) {
  formulationStatus = 'rejected';
  decisionSummary = 'Compliance check failed';
} else if (safetyAssessment.safety_status === 'fail') {
  formulationStatus = 'rejected';
  decisionSummary = 'Safety assessment failed';
}

// Determine compliance state
const complianceState = complianceCheck.compliant ? 'compliant' : 'non-compliant';

// Build approvals array
const approvals = [
  {
    approver: 'CREA',
    status: creaApproval.crea_approved ? 'approved' : 'rejected',
    timestamp: new Date().toISOString()
  },
  {
    approver: 'AFA',
    status: afaApproval.approved ? 'approved' : 'rejected',
    timestamp: new Date().toISOString()
  }
];

// Determine next allowed actions
const nextAllowedActions = [];
if (formulationStatus === 'approved') {
  nextAllowedActions.push('proceed_to_manufacturing');
  nextAllowedActions.push('notify_stakeholders');
  nextAllowedActions.push('generate_documentation');
} else {
  nextAllowedActions.push('revise_formulation');
  nextAllowedActions.push('request_reapproval');
}

// Build audit object
const audit = {
  timestamp: new Date().toISOString(),
  performed_by: 'WF-4',
  notes: [
    `Formulation ${formulationStatus}`,
    `CREA review: ${creaApproval.crea_approved ? 'approved' : 'rejected'}`,
    `AFA review: ${afaApproval.approved ? 'approved' : 'rejected'}`,
    `Compliance: ${complianceState}`,
    `Safety: ${safetyAssessment.safety_status}`
  ]
};

// Return single normalized object with ONLY specified fields
return [{
  json: {
    workflow_id: 'WF-4',
    request_id: requestId,
    status: formulationStatus === 'approved' ? 'success' : 'rejected',
    formulation_status: formulationStatus,
    decision_summary: decisionSummary,
    confidence: $('Execute Workflow Trigger').item.json.confidence,
    risk_level: inputData.risk_level || 'medium',
    compliance_state: complianceState,
    crea_reviewed: true,
    approvals: approvals,
    next_allowed_actions: nextAllowedActions,
    audit: audit
  }
}];

// Generate Immutable Audit Record
const items = $input.all();
const inputData = items[0].json;

// Extract data from previous nodes
const workflowConfig = $('Workflow Configuration').first().json;
const confidenceCheck = $('System Confidence Recheck').first().json;
const complianceState = $('Compute Compliance State').first().json;
const creaApproval = $('Call CREA Approval (WF-8)').first().json;
const afaApproval = $('AFA Final Approval Agent').first().json;

// Determine approval status and reason
let approvalStatus = 'unknown';
let approvalReason = '';
let blockReason = '';

if (afaApproval && afaApproval.approved === true) {
  approvalStatus = 'approved';
  approvalReason = afaApproval.notes || afaApproval.approval_reason || 'AFA approved formulation';
} else if (afaApproval && afaApproval.approved === false) {
  approvalStatus = 'blocked';
  blockReason = afaApproval.notes || afaApproval.rejection_reason || 'AFA rejected formulation';
} else {
  approvalStatus = 'pending';
}

// Build audit record
const auditRecord = {
  audit_id: `AUDIT-${inputData.request_id || $execution.id}-${Date.now()}`,
  request_id: inputData.request_id || $execution.id,
  mode: inputData.mode || workflowConfig.default_mode || 'simulation',
  confidence: confidenceCheck?.confidence_score || confidenceCheck?.overall_confidence || 0,
  risk_level: confidenceCheck?.risk_level || complianceState?.risk_level || 'unknown',
  compliance_state: complianceState?.compliance_state || complianceState?.status || 'unknown',
  crea_decision: {
    approved: creaApproval?.approved || creaApproval?.crea_approved || false,
    feedback: creaApproval?.feedback || creaApproval?.crea_feedback || 'No feedback provided',
    timestamp: creaApproval?.timestamp || new Date().toISOString()
  },
  afa_decision: {
    status: approvalStatus,
    approval_reason: approvalReason,
    block_reason: blockReason,
    final_formula_id: afaApproval?.final_formula_id || null,
    timestamp: new Date().toISOString()
  },
  workflow_execution_id: $execution.id,
  timestamp: new Date().toISOString(),
  immutable: true
};

return [{
  json: {
    ...inputData,
    audit_record: auditRecord
  }
}];

const items = $input.all();
const inputData = items[0]?.json || {};

const validationData = inputData.universal_contract_validation || {};
const validationError = validationData.errorMessage || 'Invalid or incomplete universal contract';
const requestId = inputData.request_id || $execution.id;

return [
  {
    json: {
      status: 'rejected',
      formulation_status: 'NOT APPROVED',
      blocked_by: 'Universal Contract Validation',
      reason: 'Invalid or incomplete universal contract - WF-4 rejected execution',
      validation_error: validationError,
      request_id: requestId,
      mode: inputData.mode || 'unknown',
      confidence: inputData.confidence || 0,
      risk_level: inputData.risk_level || 'unknown',
      timestamp: new Date().toISOString()
    }
  }
];

const items = $input.all();
const inputData = items[0]?.json || {};

const creaApproval = $('Call CREA Approval (WF-8)').first().json;

return [
  {
    json: {
      status: 'blocked',
      formulation_status: 'NOT APPROVED',
      blocked_by: 'CREA',
      crea_reviewed: true,
      crea_decision: 'rejected',
      reason: creaApproval?.feedback || creaApproval?.crea_feedback || 'CREA blocked formulation approval - non-bypassable gate',
      request_id: inputData.request_id || $('Execute Workflow Trigger').item.json.request_id || 'unknown',
      mode: inputData.mode || 'simulation',
      confidence: inputData.confidence || 0,
      risk_level: inputData.risk_level || 'high',
      timestamp: new Date().toISOString()
    }
  }
];

const items = $input.all();
const inputData = items[0]?.json || {};

const complianceCheck = $('Compliance Check Agent').first().json;

return [
  {
    json: {
      status: 'blocked',
      formulation_status: 'NOT APPROVED',
      blocked_by: 'Compliance Check',
      reason: 'Non-compliant formulation - approval blocked',
      violations: complianceCheck?.violations || inputData.violations || [],
      request_id: inputData.request_id || $('Execute Workflow Trigger').item.json.request_id || 'unknown',
      mode: inputData.mode || 'simulation',
      confidence: inputData.confidence || 0,
      risk_level: inputData.risk_level || 'high',
      compliance_state: 'non_compliant',
      timestamp: new Date().toISOString()
    }
  }
];
